var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"시청자 여러분, 미하~","JPN":"視聴者の皆さん、ミハー！","ENG":"Hi, everyone. It's me, Miya!","TWN":"各位觀眾，米婭 hi～"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"여기는 따사로운 햇살이 내리쬐는 모래사장이에요.","JPN":"こちらは眩しい日差しが差す砂浜です。","ENG":"I’m on the sunny beach now.","TWN":"這裡是陽光普照的沙灘"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"지금 이곳에서는 루미의 제안으로 기습적인 비치발리볼 대회가 열리고 있는데요.","JPN":"ここでは今、ルミの提案でビーチバレーボール大会が開かれています。","ENG":"We’re now having an unexpected beach volleyball contest here thanks to Lumi’s suggestion.","TWN":"多虧魯米的提議，現在這裡正臨時舉行沙灘排球比賽中。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"대회 협찬은 조디악 나이츠의 기사단장님께서 해 주셨어요.","JPN":"大会の開催はゾディアックナイツの騎士団長が協力してくれました。","ENG":"This event is sponsored by the captain of the Zodiac Knights.","TWN":"而這次的比賽呢，是由水瓶座騎士的騎士團長贊助。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"헤헤, 단장님. 소감 한 말씀 부탁드려도 될까요?","JPN":"ふふ、団長。一言お願いしてもいいですか？","ENG":"Hello, captain. How do you feel about this contest?","TWN":"嘿嘿，可以請團長跟我們的觀眾說句話嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"파라솔 대신 받은 배구공을 유용하게 쓸 수 있다면 그걸로 충분하다.","JPN":"パラソルの代わりに届いたバレーボールを有効に使えるなら、それで十分だ。","ENG":"If we can make use of this volleyball that we got instead of a parasol, that’s good enough.","TWN":"我訂的明明是遮陽傘，收到的卻是排球，當然還是要物盡其用！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"파라솔이 필요했던 에리어스 경도 아이들과 나들이를 나갔으니, 결과적으로는 잘됐군.","JPN":"パラソルを欲しがっていたアリウスは子どもたちと遊びに行ったから、結果的にはよかったと思う。","ENG":"Arius wanted the parasol, and is now off playing with children, so everything turned out to be okay.","TWN":"需要遮陽傘的埃里奧斯愛卿也和孩子們一起出來玩，就算是一個美麗的誤會囉～"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"모처럼 열리는 경기이니 정정당당하게 승리를 쟁취하길 바란다!","JPN":"せっかくの試合だ、みんな正々堂々と勝利を勝ち取ってほしい！","ENG":"Fight fair and square, and may the best player win!","TWN":"這麼難得的比賽，希望大家可以發揮體育精神爭取勝利！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"네, 좋은 말씀 감사합니다. 단장님.","JPN":"はい、ありがとうございます！","ENG":"Thank you, captain.","TWN":"好的，謝謝團長。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"그러면 바로 경기를 시작할게요.","JPN":"それでは試合を始めます。","ENG":"We’ll proceed with the game now.","TWN":"那麼，比賽正式開始囉！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"사회는 저 미야, 그리고 해설은…….","JPN":"司会はこのミヤ、そして解説は……","ENG":"I’m your host. And the commentator is...","TWN":"今天的主持人是我 米婭，球評呢……"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"현지인이신 드라코 님을 모셨습니다~ 박수로 환영해 주세요~","JPN":"ドラコさんに来ていただきました！　拍手で歓迎してくださいね！","ENG":"Dracasia, a local resident! Everyone, please welcome her with a great applause!","TWN":"為您邀請到的是在地人德拉克～掌聲歡迎～"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"이거 진짜 하트베리 생방 맞아? 거짓말 아냐?","JPN":"これって本当にハートベリーの生配信なの？　嘘じゃないよな？","ENG":"Am I really on the HRT Berry show? You’re not lying, are you?","TWN":"真的是愛心莓果的直播嗎？我不是在作夢吧？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"저, 정말이에요. 여기 보시면 채팅창이 드라코 님 얘기로 가득해요.","JPN":"ほ、本当ですよ。ほら、このチャット欄にドラコさんへのコメントでいっぱいでしょ？","ENG":"Y-you really are! Look at the chat, everyone is talking about you!","TWN":"是…是真的喔～你看這邊的聊天室窗，裡面有好多人提到你。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"흥. 그럼 어디 그라운드 원에서 온 삼류 용병들 실력이나 보실까.","JPN":"ふん。じゃあ、グラウンド・ワンから来た三流傭兵どもの実力を見てあげようじゃない。","ENG":"Hmpf. Okay, then. Let’s see what these third-rate mercenaries from Ground One can do.","TWN":"喔，那就一起來看看，來自G1的三流傭兵實力如何吧！？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"뭐, 어차피 어중이떠중이가 잔뜩 몰려드는 곳이니까 기대할 것도 없겠지만.","JPN":"まあ、どうせ中途半端なやつしか集まってこない所だし、期待もなにもないけど。","ENG":"Well, they’re all losers so I don’t expect much from them though.","TWN":"反正就是一群二百五的聚集，應該沒什麼好期待的。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"뭐? 내가 띠꺼워? 방금 채팅친 너 그라운드 원 출신이야?","JPN":"は？　あたしが気に食わないって？　今のコメント飛ばしたお前、グラウンド・ワン出身だろ？","ENG":"What? You don’t like me? You’re one of the Ground One residents, aren’t you?","TWN":"什麼？說我的講評很不精彩？ 你是G1來的吧？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"결투 신청은 내 SNS로도 받고 있걸랑? 허접 인증 하고 싶으면 덤벼 보시지?","JPN":"決闘申請ならあたしのSNSで受け付けてやるから！　負け犬になりたいならかかってこいよ！","ENG":"You can challenge me for a duel via my social network account. Bite me if you dare.","TWN":"我的社群平台也接受挑戰啦！想知道自己有多爛嗎？有種來戰！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"아, 그 대신에 지면 각오해. 엄청 쪽팔린 복장으로 프론트 베이 산책을 시켜 줄 테니까.","JPN":"あ、負けた時は覚悟しなよ。世界一みっともない格好をさせてフロントベイで散歩させるから。","ENG":"But if you lose, I’ll make you walk through Front Bay with an embarrassing costume.","TWN":"還有！輸的話要穿丟人的衣服在前灣散步！敢不敢啊！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"겨, 경기! 경기 시작하겠습니다!","JPN":"さ、さて！　試合を始めます！","ENG":"L-let’s start the game!","TWN":"比…比賽正式開始！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"히잉, 이나 언니이! 해설 좀 다른 분으로 바꿔 주세요! 채팅창 불나고 있어요!","JPN":"ひーん、メグミさん！　解説は他の方にチェンジできないんですか？　チャットが荒れてますよぉ！","ENG":"Inaaa! Can you please find another commentator? People are trashing the chat window!","TWN":"嗚，理娜姐！球評換個人吧？現在聊天室裡都炎上了！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L38_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"예상은 했지만 참 소란스럽네요.","JPN":"予想はしていましたが、本当に騒がしいですね。","ENG":"I kind of expected it to happen, but this is too much.","TWN":"雖然有預料到，但還真的是亂七八糟。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"한가하게 일광욕이나 즐기려고 했는데 이래서야 해변에 있을 곳이 없겠어요.","JPN":"のんびり日光浴を楽しもうとしたのに、これではビーチに居場所もありませんね。","ENG":"All I wanted was to enjoy the sun on a quiet beach, but now it’s all ruined.","TWN":"本來是想要悠閒地享受一下日光浴，但根本沒有我的立足之地。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"생각을 바꿔 보면 어떤가?","JPN":"考え方を変えてみてはどうかね？","ENG":"Try to change your perspective.","TWN":"副總換個想法怎麼樣？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L43_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"태스크포스 간의 비치발리볼이라니, 이런 친선전은 어디에서도 보기 드물지.","JPN":"タスクフォースカンパニー同士のビーチバレーだなんて、こんな親善試合は滅多に見れるものじゃない。","ENG":"It’s a rare opportunity to watch a beach volleyball contest between TASKFORCE companies.","TWN":"你看看，特遣勢力竟然聚在一起打沙灘排球？！這是多麼難得一見的友誼賽！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"건틀릿 경기라면 전술 분석 때문에 작전부와 함께 매일 시청 중입니다.","JPN":"ガントレット戦なら戦術分析のため、作戦部と一緒に毎日視聴しています。","ENG":"I’m already watching Gauntlet matches everyday with the Operations Department for strategy analysis.","TWN":"比賽的重點就是戰略分析，所以我每天都會和作戰部的同仁一起收看寶傑。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"슬슬 레나 양과 클로에 양도 경력이 쌓였으니, 이제 저는 물러나도 될 것 같지만 말이죠.","JPN":"そろそろレナさんとクロエさんも業務に慣れてきましたから、もう私は抜けてもよさそうですけどね。","ENG":"But I guess they won't be needing me anymore, since Lena and Chloe have acquired enough experience.","TWN":"現在蕾娜和克洛伊也已經累積不少經驗，我差不多是時候交棒了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하하. 물론 그래야지. 자네도 몸이 두 개는 아니지 않나.","JPN":"ハハハ。いいと思うぞ。君も多忙だからな。","ENG":"Hah hah, of course. I know you’re quite busy.","TWN":"哈哈～那是當然的囉！你又不能一人分飾多角。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"기왕 이렇게 된 거 직접 참가해 보면 어떤가?","JPN":"せっかくだし、参加してみたらどうだ？","ENG":"How about you join the contest?","TWN":"事已至此，副總不如就直接下場參加吧？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L49_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"규칙상 공정성을 위해서 카운터들은 능력을 사용해선 안 된다고 하던데.","JPN":"ルール上、公正性のためにカウンターは能力を使ってはいけないと聞いたが。","ENG":"I heard the players are not allowed to use Counter abilities.","TWN":"只是為了公平起見，制裁者不能使用能力。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"사양하겠습니다. 무심코 날린 스파이크에 누가 실려 갈지 모르니까요.","JPN":"遠慮しておきます。思わず飛ばしたスパイクで誰かが病院行きにでもなったら困りますから。","ENG":"I would rather not. I can’t hurt others by mistake.","TWN":"請恕我拒絕，我怕我一個殺球太重，會有人要進醫院。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L3_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"그러니 저는 여기 누워서 사장님께 계속 불평이나 해야겠습니다.","JPN":"なので私はここで横になって、社長にずっと文句でも言おうと思っています。","ENG":"So I’ll just stay here and keep complaining.","TWN":"我決定繼續躺在這裡跟老闆抱怨。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"부채 좀 시원하게 부쳐 주시죠. 바람이 잘 안 오네요.","JPN":"涼しさが足りません。頑張って扇いでください。風が届きませんよ。","ENG":"Could you wave the fan harder? I’m not feeling the wind here.","TWN":"請再搧大力點，扇子都沒有風。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"크흠. 내가 다 설명하지 않았나.","JPN":"コホン、だから全部説明したじゃないか。","ENG":"Ahem. Like I said...","TWN":"咳咳，我是不是沒有解釋清楚？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"기숙사에 큰 돈 들인 건 다 직원들의 근무 환경을 위해서…….","JPN":"寮に大金をかけたのはすべて社員の福利厚生のために……","ENG":"That money spent on the Dorm was for the sake of our employees...","TWN":"宿舍之所以會花那麼多經費，全是為了員工的工作環境……"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"저도 그렇게 믿었습니다.","JPN":"私もそう信じていましたよ。","ENG":"That’s what I believed.","TWN":"我也以為是那樣。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"영수증에 찍힌 항목 중에 그 깡통을 닮은 순금 동상을 발견하기 전까지는요.","JPN":"領収書に印刷された項目の中から、そのボロ缶に似た純金像を見つけるまでは。","ENG":"Until I found a golden statue of that tin can in the receipt list.","TWN":"直到我在收據的明細上，發現那個長得像罐頭一樣的純金雕像。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"크흠! 흠! 흠!","JPN":"ゴホン、ゴホン！","ENG":"Ahem! Hmm! Hmm!","TWN":"咳咳！咳！咳！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"대체 왜 그렇게까지 그 깡통에 집착하시는지 모르겠군요.","JPN":"いったいなぜ、そこまでそのボロ缶に執着されるのか理解できません。","ENG":"I don’t understand why you’re so obsessed with the tin can.","TWN":"雖然我不明白為什麼老闆對那個罐頭那麼執著，"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"물론 취향은 존중해 줘야죠. 독단으로 회사 재정에 타격을 입힌 잘못과는 별개로.","JPN":"もちろん好みは尊重しているつもりです。独断で会社財政に損害を負わせた過ちとは別ですが。","ENG":"I do respect your taste. Regardless of the financial damage you incurred to our company.","TWN":"但撇開老闆擅自打擊公司的財政不說，我還是必須尊重老闆的興趣。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"네, 시청자 여러분. 지금까지 예선전은 순조롭게 진행되고 있네요.","JPN":"はい、視聴者の皆さん。今のところ予選は順調に進んでいますね。","ENG":"Okay, viewers. So far the preliminary matches are going extremely well.","TWN":"是的，觀眾朋友們，目前預賽順利進行中。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"그러면……. 계속해서 다음 경기인데요.","JPN":"では……続けて次の試合です。","ENG":"Now, the next match...","TWN":"接下來……緊接著是下一場比賽，"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"소개합니다. 우리 하트베리의 잠꾸러기 보미와……","JPN":"ご紹介します。ハートベリーのお寝坊さん、ボミと……","ENG":"Let me introduce you the players. Bomi, the sleepyhead of HRT Berry...","TWN":"為您介紹！我們愛心莓果的瞌睡蟲 普美，以及……"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"이수연 선수!","JPN":"カナミ・キズナ選手！","ENG":"And Lee Sooyeon!","TWN":"李秀妍選手！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"어? 코핀 컴퍼니에도 이름이 같은 분이 계셨던 것 같은데……?","JPN":"あれ？　コフィンカンパニーにも同じ名前の方がいたような……？","ENG":"Huh? I think they have Lee Sooyeon in Coffin Company as well.","TWN":"嗯？我記得科芬公司裡也有一位同名同姓的人……？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"흠냐앙……. 루미는 왜 자기가 출전하자고 해 놓고 예선에서 탈락해 버리냥…….?","JPN":"ふわあ……ルミはなんで自分から出場しようと言ってたのに、予選で落ちてしまうにゃん……？","ENG":"*Yawn* ... Lumi was the one who dragged me into this, and she got eliminated in the preliminary round...","TWN":"哈啊……魯米真是的，自己說要上場，結果在預賽就被淘汰了喵……？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"정신 차려, 고양아! 우리가 나갈 차례야!","JPN":"しっかりして、猫ちゃん！　私たちの番よ！","ENG":"Wake up, kitty! It’s our time to go!","TWN":"貓咪，打起精神來！該我們上場囉！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"………….","JPN":"…………","ENG":"...","TWN":"…………"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"원래 있던 곳으로 돌아갔다느니 어쩌니 하지 않으셨나요?","JPN":"元の場所に戻ったとお聞きしましたが。","ENG":"Didn’t you say she went back to where she came from?","TWN":"不是說要回到原本的地方嗎？這是怎麼回事？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하. 하하. 과학은 수많은 변수 속에서 끊임없는 가설과 증명을 통해 진리를 밝혀내야 한다네.","JPN":"ア・ハ・ハ。科学は数多くの変数の中で繰り返される仮説や証明を通じて真理を解き明かさなければならない。","ENG":"Hah, hah hah. Science involves the continuous formation of new theories and the verification of existing theories. And there are so many variables that can affect the outcome.","TWN":"哈…哈哈…科學就是在無數的變數中，不斷藉由假設和驗證找出真理的嘛～"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"가끔은 저런 예상치 못한 변수가 등장할 때도 있는 법이지.","JPN":"稀に、あんな予想外の変数が登場する時もあるのさ。","ENG":"And I think she’s one of those unexpected variables.","TWN":"偶爾也是會出現預料之外的變數嘛～"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"뭔가요, 그 고무줄 같은 기준은.","JPN":"なんですか、その適当な基準は。","ENG":"That doesn’t sound very trustworthy.","TWN":"是什麼呢？你那模擬兩可的標準說來聽聽？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L30_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"으음. 나도 이런 얘기는 하기 싫지만, 저 시절의 자네가 보유한 CRF 출력이면 충분히 커다란 변수라네.","JPN":"うーん、私もこんな話はしたくないが、あの頃の君が保有していたCRF出力なら十分大きな変数だ。","ENG":"I don’t want to say this to you, but your CFR output from that period of time can actually be a major variable.","TWN":"嗯，我不太想這麼說，但你那個時後持有的CRF輸出，確實是很大的變數。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"그러면 당장 돌려보낼 방법부터 증명하셔야겠습니다.","JPN":"それでは今すぐ帰す方法を証明していただきたいです。","ENG":"Well, you have to find a way to send her back.","TWN":"那就請你先以身試法吧。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"배달부가 가져 온 리액티브 소드는 아직 제 손에 있으니까요.","JPN":"配達員が持ってきたリアクティブソードはまだ私の手元にありますから。","ENG":"I still have the Reactive Sword that the deliverywoman brought me.","TWN":"反正剛剛外送員拿來的反應劍還在我手中。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"너, 너무 과민 반응하지 말게! 저러다가 조용히 사라질 수도 있는 거지!","JPN":"そ、そんなに敏感に反応する必要ないじゃないか！　そのうち静かに消えるかもしれないしな。","ENG":"S-stop overreacting! She could just disappear in time!","TWN":"你反應不要這麼激烈！說不定他們等一下就會自己乖乖回去。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"하음~ 햇살이 따뜻해서 너무 나른하다냥~ 고양이라 어쩔 수 없어냥~","JPN":"にゃ～、日差しが温かすぎてだるいにゃ～。猫だから仕方ないにゃーん。","ENG":"*Yawn* It’s so warm, I feel drowsy... I’m a cat, I can’t help it...","TWN":"哈啊～陽光好溫暖好想睡喔～沒辦法～誰叫我是貓呢～"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"흐음. 정 그렇다면 어쩔 수 없네.","JPN":"ふーん、なら仕方ない。","ENG":"Hmpf. If that’s the case.","TWN":"哼！沒辦法！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"이 이수연 님이 혼자 돌파해 주겠어!","JPN":"このカナミ・キズナ様が一人で突破してやる！","ENG":"I’ll deal with this all by myself!","TWN":"只好由我李秀妍一個打十個！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"노리는 건 오로지 우승! 스승님께 꼭 트로피를 전해 드릴 거야!","JPN":"狙うのは優勝のみ！　師匠に必ずトロフィーを捧げる！","ENG":"My only goal is the victory! I will give the trophy to the Master!","TWN":"我的目標只有冠軍！我要把獎盃送給師父！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"참고로 트로피는 이 귀여운 펭귄이라네요.","JPN":"ちなみにトロフィーはこの可愛いペンギンらしいです。","ENG":"For your information, the trophy is a cute penguin.","TWN":"話說，獎盃就是這個可愛的企鵝喔。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"},"C":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"이거 좀 어디다 치우면 안 돼? 난 얘들 보기만 해도 쏠리거든?","JPN":"ねえ、これどっかにどかしておいてもいい？　この子たちを見るだけで気分が悪くなるんだけど。","ENG":"Can you please put it away? I don’t want to see any more penguins.","TWN":"這個可以拿走嗎？我光看到就覺得礙眼！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"큰일입니다. 저대로 두면 사태가 빚덩이처럼 커지겠어요.","JPN":"大変です。あのままだと、また大騒ぎになりそうです。","ENG":"It’s not good. The situation is snowballing like our bank loan.","TWN":"大事不妙！再這樣下去，失分會跟債務一樣越滾越大！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"우, 우선 방송에 나가는 내용은 다─크 세븐을 통해 변조해 뒀다네.","JPN":"と、とりあえず放送に流れる内容はダークセブンを通じて手を加えておいた。","ENG":"I-I’ve asked the Daark Seven to manipulate the broadcasting signal.","TWN":"總之，Dark 7已經動過直播出去的內容。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그렇지만 확실히 저대로 두기에는 곤란하군.","JPN":"しかし、確かにあのまま放っておくのはリスキーだな。","ENG":"But you’re right. We can’t let her go on like this.","TWN":"但確實這樣下去會很難看！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L50_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"하아…….","JPN":"はあ……","ENG":"*Sigh*","TWN":"哎……"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L1_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"좋습니다. 제가 나서야겠군요.","JPN":"いいです。私がやります。","ENG":"Okay. I’ll step in.","TWN":"好，我來吧！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L2_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"아무렇지 않게 예선전에서 탈락시켜 버리겠습니다.","JPN":"さりげなく予選で脱落させておきます。","ENG":"I’ll knock her out in the preliminary.","TWN":"我會讓對手三兩下就從預賽中淘汰！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L3_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"음? 2인 1조인데 다른 선수를 갑자기 어디서 구하려고?","JPN":"うむ？　2人1組なのに他の選手をどこで探すんだ？","ENG":"Huh? It’s a doubles match. Where will you find a partner?","TWN":"不過要兩人一組欸？你臨時要上哪去找選手？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"굳이 구하러 다닐 필요는 없겠군요.","JPN":"探しに行く必要はなさそうです。","ENG":"Don’t worry about it.","TWN":"遠在天邊近在眼前！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"마침 서로 알 만큼 다 아는 파트너가 여기 있으니까요.","JPN":"事情が分かるパートナーがここにいますから。","ENG":"I happen to have a partner here who is close enough.","TWN":"最熟悉彼此的夥伴不就在這裡嗎！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"갑작스레 미안하지만, 경기 참가하겠습니다.","JPN":"急で申し訳ありませんが、試合に参加します。","ENG":"Excuse us, we’re participating in the contest.","TWN":"雖然有點突然，但我要參加比賽。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"앗, 저기, 갑작스럽게 선수가 난입했는데요.","JPN":"あっ、いきなり選手が乱入してきましたね。","ENG":"Oh, um, it looks like new players jumped in.","TWN":"喔！突然有選手亂入！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"네? 이나 언니? 재밌어 보이니까 그대로 진행하자고요?","JPN":"え？　メグミさん？　面白そうだからこのまま進行しますって？","ENG":"What did you say, Ina? We can just go on because it looks fun?","TWN":"嗯？理娜姐？感覺很精彩不要關掉直播嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"뭐야? 저 사장님 아직 복귀 안 했잖아?","JPN":"なんだ？　あの社長、まだ帰ってなかったのか？","ENG":"Huh? That robot CEO is still here?","TWN":"搞什麼？那個老闆還沒回歸不是嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"미리 알았으면 나도 선수로 참가하는 건데……!","JPN":"知ってたらあたしも選手で参加したのに……！","ENG":"I would have participated in the contest if I had known it!","TWN":"早知道我也去當選手啦……！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"부사장, 자네 지금 실수하는 걸세!","JPN":"副社長、君は今理性を失いかけている！","ENG":"Vice President, you’re making a mistake!","TWN":"副總，你正在犯下滔天大錯！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"델리케잇한 공학기술의 결정체인 머신-갑-로보 Mk.2를 이렇게 거칠게 다루다니!","JPN":"デリケートな工学技術の結晶であるマシーン-甲-Mk.2ロボにこんな手荒な扱いをするなんて！","ENG":"Don’t be so rough with Machine G.A.P. R.B. Mk.2! This is a delicate state-of-the art machine!","TWN":"竟然用如此粗糙的手法操控精密工學技術的產物，機-甲-機器人 Mk.2！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"계속 싫다고 하시면 저 흑역사한테 배구공 대신 날려 드리겠습니다.","JPN":"拒否し続けるなら、バレーボールの代わりにあの黒歴史に飛ばしてあげますよ。","ENG":"If you keep saying no, I will smash you away to that girl from the darkest time of my life.","TWN":"你再吵，我就把你當排球打！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"넵.","JPN":"はいっ。","ENG":"Yes, ma’am.","TWN":"我乖乖！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"응? 아줌마가 나랑 붙는다고?","JPN":"え？　おばさんが私の相手？","ENG":"What? You’re fighting me, old lady?","TWN":"嗯？大嬸要和我對打喔？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"아줌마라는 호칭 그만두시죠.","JPN":"そのおばさんという呼び方はやめてください。","ENG":"Stop calling me an old lady.","TWN":"不要叫我大嬸。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"그쪽도 젊다고 방심했다가는 격무에 시달리다 어느새 피부 탄력을 잃어 버릴 테니까요.","JPN":"あなたも若いと油断していたら激務に苦しめられ、いつの間にか肌の弾力を失ってしまいますからね。","ENG":"Being young won’t protect your skin if you work hard all the time.","TWN":"不要以為你還年輕，等你之後進入職場，就會知道膠原蛋白流失得有多快。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"걱정해 줘서 고마워. 그러려면 아직 한참 남았지만.","JPN":"心配ありがとう。でもまだ遠い将来の話なんだけどね。","ENG":"Thank you for the advice, but I’m far too young to worry about such things.","TWN":"謝謝你替我擔心，雖然對我來說還很遙遠。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"그보다 지금이라도 기권하는 게 좋을걸?","JPN":"それより、今からでも棄権した方がいいと思うよ。","ENG":"I suggest you give up now.","TWN":"不過我勸你們還是投降吧！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"펜릴 전대의 이수연 님 사전에 패배란 없으니까!","JPN":"フェンリル戦隊のカナミ・キズナの辞書に敗北という言葉はない！","ENG":"I, Lee Sooyeon of the FENRIR Division, never lose!","TWN":"因為在芬里爾戰隊李秀妍的字典裡，沒有輸！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"그 안이한 마음가짐은 이 기회에 확실히 제대로 손봐 줘야겠군요.","JPN":"その安易なマインドは、この機会にきちんと直してもらわねばなりませんね。","ENG":"I think it’s a good opportunity to correct your arrogant attitude.","TWN":"我就趁這個機會挫挫你的銳氣！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"덤비시죠. 경험의 차이를 실감하게 만들어 주겠습니다.","JPN":"かかってきなさい。人生経験の差を実感させてあげます。","ENG":"Come. I’ll show you how experience makes a difference.","TWN":"放馬過來吧！我吃過的鹽可是比你吃過的米還多！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"좋아! 그렇다면 나도 사정 안 봐 줄게!","JPN":"よし！　なら私も容赦なくいくよ！","ENG":"Okay, then. I won’t hold back!","TWN":"很好！我可不會手下留情喔！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"그런데 시작하려면 어떻게 해야 돼?","JPN":"ところで、始めるには何をすればいいの？","ENG":"How do I start?","TWN":"那現在是要怎樣？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"흐아암……. 서브부터 하라냥…….","JPN":"ふわあ……サーブからやるにゃん……","ENG":"*Yawn* Start with a serve...","TWN":"哈啊……先發球啊喵……"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};